import React, { useMemo } from 'react';

interface Column {
  key: string;
  label: string;
  sortable?: boolean;
  render?: (value: any, row: any) => React.ReactNode;
}

interface DataGridConfig {
  pageSize: number;
  sortField: string;
  sortDirection: 'asc' | 'desc';
  highlightThreshold?: number;
}

interface DataGridProps {
  data: any[];
  columns: Column[];
  config: DataGridConfig;
  page: number;
  onPageChange: (page: number) => void;
}

export function DataGrid({ data, columns, config, page, onPageChange }: DataGridProps) {
  const processedData = useMemo(() => {
    const sorted = [...data].sort((a, b) => {
      const aVal = a[config.sortField];
      const bVal = b[config.sortField];
      const cmp = aVal > bVal ? 1 : aVal < bVal ? -1 : 0;
      return config.sortDirection === 'desc' ? -cmp : cmp;
    });

    const start = page * config.pageSize;
    const paginated = sorted.slice(start, start + config.pageSize);

    if (config.highlightThreshold !== undefined) {
      return paginated.map(row => ({
        ...row,
        _highlighted: row.value > config.highlightThreshold,
      }));
    }

    return paginated;
  }, [data, columns, config, page]);

  return (
    <table>
      <thead>
        <tr>
          {columns.map(col => (
            <th key={col.key}>{col.label}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {processedData.map((row, i) => (
          <tr key={row.id ?? i} className={row._highlighted ? 'highlighted' : ''}>
            {columns.map(col => (
              <td key={col.key}>
                {col.render ? col.render(row[col.key], row) : row[col.key]}
              </td>
            ))}
          </tr>
        ))}
      </tbody>
      <tfoot>
        <tr>
          <td colSpan={columns.length}>
            <button disabled={page === 0} onClick={() => onPageChange(page - 1)}>Prev</button>
            <span>Page {page + 1}</span>
            <button onClick={() => onPageChange(page + 1)}>Next</button>
          </td>
        </tr>
      </tfoot>
    </table>
  );
}

