import React from 'react';

interface ExternalLinkProps {
  url: string;
  label: string;
  className?: string;
  showIcon?: boolean;
}

export function ExternalLink({ url, label, className, showIcon = true }: ExternalLinkProps) {
  if (!url || !url.trim()) {
    return <span className={className}>{label}</span>;
  }

  const displayUrl = url.length > 50 ? url.slice(0, 47) + '...' : url;

  return (
    <a
      href={url}
      className={className}
      target="_blank"
      rel="noopener noreferrer"
      title={displayUrl}
    >
      {label}
      {showIcon && <span className="external-icon" aria-hidden="true"> ↗</span>}
    </a>
  );
}

