import React from 'react';

interface RichContentProps {
  html: string;
  className?: string;
  allowImages?: boolean;
}

const BLOCKED_TAGS = [
  'script', 'iframe', 'object', 'embed', 'form',
  'input', 'textarea', 'select', 'button',
];

function sanitize(html: string, allowImages: boolean): string {
  let clean = html;

  for (const tag of BLOCKED_TAGS) {
    const openPattern = new RegExp(`<${tag}\b[^>]*>`, 'gi');
    const closePattern = new RegExp(`</${tag}>`, 'gi');
    clean = clean.replace(openPattern, '').replace(closePattern, '');
  }

  if (!allowImages) {
    clean = clean.replace(/<img [^>]*>/gi, '');
  }

  clean = clean.replace(/<!--[\s\S]*?-->/g, '');

  return clean;
}

export function RichContent({ html, className, allowImages = true }: RichContentProps) {
  const sanitized = sanitize(html, allowImages);

  return (
    <div
      className={className}
      dangerouslySetInnerHTML={{ __html: sanitized }}
    />
  );
}

